function useLegacyWarning(componentName) {
  useEffect(() => {
    const message = `[${componentName}] This component previously relied on componentDidMount. ` +
      'It has been migrated to useEffect. If you see this message, the migration is working.';
    if (process.env.NODE_ENV !== 'production') {
      console.warn(message);
    }
  }, [componentName]);
}
